import React from 'react';
import { Text, View } from 'react-native';

import type {
  KangurAiTutorConversationContext,
  KangurAiTutorNativeGuideEntry,
} from '../../../../src/shared/contracts/kangur-ai-tutor';
import type { KangurMobileLocale } from '../i18n/kangurMobileI18n';
import type { useKangurMobileAiTutor } from './useKangurMobileAiTutor';
import {
  useKangurMobileI18n,
} from '../i18n/kangurMobileI18n';
import { StatusPill, OutlineLink } from '../shared/KangurAssessmentUi';
import {
  KangurMobileActionButton,
  KangurMobileCard,
  KangurMobileInsetPanel,
} from '../shared/KangurMobileUi';
import { useKangurMobileAiTutor } from './useKangurMobileAiTutor';

type KangurMobileAiTutorCardProps = {
  context: KangurAiTutorConversationContext;
  gameTarget?: 'competition' | 'practice';
};

type ResponseAction = ReturnType<typeof useKangurMobileAiTutor>['responseActions'][number];

const resolveCopy = (locale: KangurMobileLocale): {
  openPractice: string;
} => ({
  de: 'Open:',
  en: 'Open:',
  pl: 'Otwórz:',
}[locale]);

const TutorHeader = ({ name, availabilityLabel, availabilityTone, usageLabel }: {
  name: string;
  availabilityLabel: string;
  availabilityTone: { backgroundColor: string; borderColor: string; textColor: string };
  usageLabel: string | null;
}): React.JSX.Element => (
  <View style={{ gap: 8 }}>
    <Text accessibilityRole='header' style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
      {`${name} · AI Tutor`}
    </Text>
    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
      <StatusPill label={availabilityLabel} tone={availabilityTone} />
      {usageLabel !== null && (
        <StatusPill
          label={usageLabel}
          tone={{ backgroundColor: '#f8fafc', borderColor: '#cbd5e1', textColor: '#475569' }}
        />
      )}
    </View>
  </View>
);

const TutorGuide = ({ guideEntry, responseMessage, isLoading, copy }: {
  guideEntry: KangurAiTutorNativeGuideEntry | null;
  responseMessage: string | null;
  isLoading: boolean;
  copy: (v: { de: string; en: string; pl: string }) => string;
}): React.JSX.Element => {
  if (guideEntry !== null) {
    return (
      <View style={{ gap: 8 }}>
        <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '700' }}>{guideEntry.title}</Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {responseMessage ?? guideEntry.shortDescription}
        </Text>
        {responseMessage === null && (
          <Text style={{ color: '#334155', fontSize: 14, lineHeight: 20 }}>
            {guideEntry.fullDescription}
          </Text>
        )}
      </View>
    );
  }

  const loadingMsg = copy({
    de: 'Der Tutor lädt die Hinweise für diesen Schritt.',
    en: 'AI Tutor is loading guidance for this step.',
    pl: 'AI Tutor ładuje wskazówki do tego kroku.',
  });
  const waitingMsg = copy({
    de: 'Der Tutor passt die Hinweise für diesen Schritt an, sobald mehr Kontext verfügbar ist.',
    en: 'AI Tutor will adapt guidance for this step once more context is available.',
    pl: 'AI Tutor dopasuje wskazówki do tego kroku, gdy pojawi się więcej kontekstu.',
  });

  return (
    <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
      {isLoading ? loadingMsg : waitingMsg}
    </Text>
  );
};

const ActionHint = ({
  copy,
  locale,
}: {
  copy: (v: { de: string; en: string; pl: string }) => string;
  locale: KangurMobileLocale;
}): React.JSX.Element => {
  const prefix = resolveCopy(locale);
  const websiteLabel = copy({ de: 'Sie haben keine weiteren Aktionen.', en: 'No actions available.', pl: 'Brak dodatkowych akcji.' });
  return <Text style={{ color: '#64748b', fontSize: 12 }}>{`${prefix} ${websiteLabel}`}</Text>;
};

const ResponseActionsPanel = ({
  actions,
  locale,
  copy,
}: {
  actions: ResponseAction[];
  locale: KangurMobileLocale;
  copy: (v: { de: string; en: string; pl: string }) => string;
}): React.JSX.Element => {
  if (actions.length === 0) {
    return <ActionHint copy={copy} locale={locale} />;
  }

  return (
    <View style={{ gap: 8 }}>
      <Text style={{ color: '#334155', fontSize: 12, fontWeight: '700' }}>
        {copy({
          de: 'Weitere Wege',
          en: 'More options',
          pl: 'Więcej opcji',
        })}
      </Text>
      {actions.map((action) => (
        <OutlineLink
          href={action.href}
          hint={action.reason ?? undefined}
          label={action.label}
          key={action.id}
        />
      ))}
    </View>
  );
};

type AvailabilityInfo = {
  tone: { backgroundColor: string; borderColor: string; textColor: string };
  label: string;
};

const resolveAvailabilityInfo = (
  state: string,
  copy: (v: { de: string; en: string; pl: string }) => string,
): AvailabilityInfo => {
  if (state === 'available') {
    return {
      tone: { backgroundColor: '#ecfdf5', borderColor: '#a7f3d0', textColor: '#047857' },
      label: copy({ de: 'Aktywny', en: 'Ready', pl: 'Aktywny' }),
    };
  }
  if (state === 'restoring_sign_in') {
    return {
      tone: { backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' },
      label: copy({ de: 'Przywracamy logowanie', en: 'Restoring sign-in', pl: 'Przywracamy logowanie' }),
    };
  }
  if (state === 'signed_out') {
    return {
      tone: { backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' },
      label: copy({ de: 'Zaloguj się', en: 'Sign in', pl: 'Zaloguj się' }),
    };
  }
  return {
    tone: { backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' },
    label: copy({ de: 'Niedostępny', en: 'Unavailable now', pl: 'Teraz niedostępny' }),
  };
};

export function KangurMobileAiTutorCard({
  context,
  gameTarget = 'practice',
}: KangurMobileAiTutorCardProps): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const tutor = useKangurMobileAiTutor({ context, gameTarget });

  const { tone: availabilityTone, label: availabilityLabel } = resolveAvailabilityInfo(
    tutor.availabilityState,
    copy,
  );

  const showLocaleOpen = resolveCopy(locale);
  let usageLabel: string | null = null;
  if (tutor.usage !== null) {
    usageLabel = tutor.usage.dailyMessageLimit === null
      ? `Today ${tutor.usage.messageCount}`
      : `Today ${tutor.usage.messageCount}/${tutor.usage.dailyMessageLimit}`;
  }

  return (
    <KangurMobileCard gap={12} padding={20}>
      <TutorHeader
        name={tutor.tutorName}
        availabilityLabel={availabilityLabel}
        availabilityTone={availabilityTone}
        usageLabel={usageLabel}
      />

      <TutorGuide
        guideEntry={tutor.guideEntry}
        responseMessage={tutor.responseMessage}
        isLoading={tutor.isLoading}
        copy={copy}
      />

      {tutor.websiteHelpTarget !== null && (
        <View>
          <OutlineLink
            href={tutor.websiteHelpTarget.href}
            hint={copy({
              de: 'Hilfeseite öffnen.',
              en: 'Opens help content.',
              pl: 'Otwiera stronę pomocy.',
            })}
            label={copy({
              de: `${showLocaleOpen} ${tutor.websiteHelpTarget.label}`,
              en: `${showLocaleOpen} ${tutor.websiteHelpTarget.label}`,
              pl: `${showLocaleOpen} ${tutor.websiteHelpTarget.label}`,
            })}
          />
        </View>
      )}

      {tutor.responseActions.length > 0 ? (
        <KangurMobileInsetPanel gap={8} padding={16}>
          <ResponseActionsPanel copy={copy} locale={locale} actions={tutor.responseActions} />
        </KangurMobileInsetPanel>
      ) : null}

      {tutor.guideEntry?.hints !== undefined && tutor.guideEntry.hints.length > 0 && (
        <KangurMobileInsetPanel gap={8} padding={16}>
          <Text style={{ color: '#0f172a', fontSize: 14, fontWeight: '700' }}>
            {copy({ de: 'Wskazówki startowe', en: 'Starter hints', pl: 'Wskazówki startowe' })}
          </Text>
          {tutor.guideEntry.hints.slice(0, 2).map((hint) => (
            <Text key={hint} style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>
              {`• ${hint}`}
            </Text>
          ))}
        </KangurMobileInsetPanel>
      )}

      {tutor.quickActions.length > 0 && (
        <View style={{ flexDirection: 'column', gap: 8 }}>
          {tutor.quickActions.map((action) => (
            <KangurMobileActionButton
              accessibilityLabel={action.label}
              centered
              disabled={!tutor.canSendMessages || tutor.isSending}
              key={action.id}
              label={action.label}
              minHeight={44}
              onPress={() => {
                void tutor.sendQuickAction(action.id);
              }}
              tone='secondary'
            />
          ))}
        </View>
      )}
    </KangurMobileCard>
  );
}

import { Text } from 'react-native';

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import {
  KangurMobileCard as Card,
} from '../shared/KangurMobileUi';
import {
  resolveSeriesWins,
  formatSeriesProgress,
  formatSeriesSummary
} from './utils/duels-ui';
import { type UseKangurMobileDuelSessionResult as DuelSessionState } from './useKangurMobileDuelSession';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

type DuelSessionSeriesCardProps = {
  copy: DuelCopy;
  duel: DuelSessionState;
  locale: DuelLocale;
};

export function DuelSessionSeriesCard({
  copy,
  duel,
  locale,
}: DuelSessionSeriesCardProps): React.JSX.Element {
  if (!duel.session?.series) {
    return <></>;
  }

  return (
    <Card>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
        {copy({
          de: 'Serie',
          en: 'Series',
          pl: 'Seria',
        })}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {formatSeriesProgress(duel.session.series, locale)}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '700' }}>
        {formatSeriesSummary(duel.session.series, locale)}
      </Text>
      {duel.session.series.leaderLearnerId !== null ? (
        <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>
          {copy({
            de: `Führt ${duel.session.players.find((player) => player.learnerId === duel.session.series.leaderLearnerId)?.displayName ?? 'unbekannt'} ${resolveSeriesWins(duel.session.series, duel.session.series.leaderLearnerId)}:${Object.entries(duel.session.series.winsByPlayer).reduce((total, [playerId, wins]) => playerId === duel.session.series.leaderLearnerId ? total : total + (typeof wins === 'number' ? wins : 0), 0)}.`,
            en: `Leading ${duel.session.players.find((player) => player.learnerId === duel.session.series.leaderLearnerId)?.displayName ?? 'unknown'} ${resolveSeriesWins(duel.session.series, duel.session.series.leaderLearnerId)}:${Object.entries(duel.session.series.winsByPlayer).reduce((total, [playerId, wins]) => playerId === duel.session.series.leaderLearnerId ? total : total + (typeof wins === 'number' ? wins : 0), 0)}.`,
            pl: `Prowadzi ${duel.session.players.find((player) => player.learnerId === duel.session.series.leaderLearnerId)?.displayName ?? 'nieznany'} ${resolveSeriesWins(duel.session.series, duel.session.series.leaderLearnerId)}:${Object.entries(duel.session.series.winsByPlayer).reduce((total, [playerId, wins]) => playerId === duel.session.series.leaderLearnerId ? total : total + (typeof wins === 'number' ? wins : 0), 0)}.`,
          })}
        </Text>
      ) : null}
    </Card>
  );
}

import { Text, View } from 'react-native';
import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { translateKangurMobileActionLabel } from '../../shared/translateKangurMobileActionLabel';
import type { KangurMobileHomeAssignmentItem } from '../useKangurMobileHomeAssignments';
import { OutlineLink, SummaryChip } from '../homeScreenPrimitives';

function getPriorityConfig(
  priority: string | undefined,
  copy: (args: Record<string, string>) => string,
): { accent: 'rose' | 'amber' | 'blue'; label: string } {
  if (priority === 'high') {
    return { accent: 'rose' as const, label: copy({ de: 'Hohe Priorität', en: 'High priority', pl: 'Priorytet wysoki' }) };
  }
  if (priority === 'medium') {
    return { accent: 'amber' as const, label: copy({ de: 'Mittlere Priorität', en: 'Medium priority', pl: 'Priorytet średni' }) };
  }
  return { accent: 'blue' as const, label: copy({ de: 'Niedrige Priorität', en: 'Low priority', pl: 'Priorytet niski' }) };
}

export function AssignmentCard({
  item,
}: {
  item: KangurMobileHomeAssignmentItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const assignment = 'assignment' in item && item.assignment !== undefined
    ? (item as { assignment: KangurMobileHomeAssignmentItem }).assignment
    : item;
  const actionLabel = translateKangurMobileActionLabel(assignment?.action?.label ?? '', locale);
  const { accent, label } = getPriorityConfig(assignment.priority, copy);

  const assignmentAction = item.href !== null ? (
    <OutlineLink href={item.href} hint={assignment.description} label={actionLabel} />
  ) : (
    <View
      style={{
        alignSelf: 'flex-start',
        borderRadius: 999,
        backgroundColor: '#e2e8f0',
        paddingHorizontal: 14,
        paddingVertical: 10,
      }}
    >
      <Text style={{ color: '#475569', fontWeight: '700' }}>
        {actionLabel} · {copy({ de: 'bald', en: 'soon', pl: 'wkrotce' })}
      </Text>
    </View>
  );

  return (
    <View
      style={{
        backgroundColor: '#f8fafc',
        borderColor: '#e2e8f0',
        borderRadius: 20,
        borderWidth: 1,
        gap: 10,
        padding: 14,
      }}
    >
      <SummaryChip accent={accent} label={label} />
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        {assignment.title}
      </Text>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {assignment.description}
      </Text>
      <Text style={{ color: '#64748b', lineHeight: 20 }}>
        {copy({ de: `Ziel: ${assignment.target}`, en: `Goal: ${assignment.target}`, pl: `Cel: ${assignment.target}` })}
      </Text>
      {assignmentAction}
    </View>
  );
}

import { Text, View } from 'react-native';

import {
  OutlineLink,
  SectionCard,
} from '../homeScreenPrimitives';
import { AssignmentCard } from './AssignmentCard';
import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { useKangurMobileHomeAssignments } from '../useKangurMobileHomeAssignments';
import { PLAN_ROUTE } from '../home-screen-constants';

export function HomeSecondaryInsightsPlanSection(): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  const homeAssignments = useKangurMobileHomeAssignments();

  return (
    <SectionCard
      title={copy({
        de: 'Plan zum Start',
        en: 'Plan from home',
        pl: 'Plan z ekranu głównego',
      })}
    >
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: 'Verwandle Fortschritt und gespeicherte Lektionen direkt in die nächsten Schritte.',
          en: 'Turn progress and saved lessons directly into the next steps.',
          pl: 'Zamień postęp i zapisane lekcje bezpośrednio w kolejne kroki.',
        })}
      </Text>
      {homeAssignments.assignmentItems.length === 0 ? (
        <Text style={{ color: '#475569', lineHeight: 20 }}>
          {copy({
            de: 'Es gibt noch keine Aufgaben. Öffne eine Lektion oder schließe ein Training ab, um sie zu erzeugen.',
            en: 'There are no tasks yet. Open a lesson or finish practice to generate them.',
            pl: 'Nie ma jeszcze zadań. Otwórz lekcję albo ukończ trening, aby je wygenerować.',
          })}
        </Text>
      ) : (
        <View style={{ gap: 12 }}>
          {homeAssignments.assignmentItems.map((item, index) => (
            <AssignmentCard
              key={
                'assignment' in item && item.assignment !== undefined
                  ? item.assignment.id
                  : item.id ?? index
              }
              item={item}
            />
          ))}
          <OutlineLink
            href={PLAN_ROUTE}
            hint={copy({
              de: 'Öffnet den vollständigen Tagesplan mit der erweiterten Aufgabenliste.',
              en: 'Opens the full daily plan with the extended task list.',
              pl: 'Otwiera pełny plan dnia z rozszerzoną listą zadań.',
            })}
            label={copy({
              de: 'Vollen Tagesplan öffnen',
              en: 'Open full daily plan',
              pl: 'Otwórz pełny plan dnia',
            })}
          />
        </View>
      )}
    </SectionCard>
  );
}

import type { KangurDuelLobbyEntry } from '@kangur/contracts/kangur-duels';
import { Pressable, Text, View } from 'react-native';

import {
  DuelInviteCard,
} from './home-duel-section-cards-1';
import {
  DuelLeaderboardEntryCard,
  RecentOpponentCard,
} from './home-duel-section-cards-2';
import { type KangurMobileLocale, type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { formatKangurMobileScoreOperation } from '../scores/mobileScoreSummary';
import {
  formatHomeRelativeAge,
  getHomeDuelDifficultyLabel,
  getHomeDuelModeLabel,
  getHomeDuelSeriesLabel,
} from './homeScreenLabels';

type CardCopy = ReturnType<typeof useKangurMobileI18n>['copy'];

const extractText = (copy: CardCopy, fallback: string): string =>
  copy({
    de: fallback,
    en: fallback,
    pl: fallback,
  });

const getModeOperationLine = (
  copy: CardCopy,
  entry: KangurDuelLobbyEntry,
  locale: KangurMobileLocale,
): string => {
  return `${getHomeDuelModeLabel(entry.mode, locale)} • ${formatKangurMobileScoreOperation(entry.operation, locale)} • ${copy({
    de: 'Stufe',
    en: 'level',
    pl: 'poziom',
  })} ${getHomeDuelDifficultyLabel(entry.difficulty, locale)}`;
};

const getUpdatedLine = (
  copy: CardCopy,
  entry: KangurDuelLobbyEntry,
  locale: KangurMobileLocale,
): string =>
  copy({
    de: `${entry.questionCount} Fragen • ${entry.timePerQuestionSec}s pro Frage • aktualisiert ${formatHomeRelativeAge(entry.updatedAt, locale)}`,
    en: `${entry.questionCount} questions • ${entry.timePerQuestionSec}s per question • updated ${formatHomeRelativeAge(entry.updatedAt, locale)}`,
    pl: `${entry.questionCount} pytań • ${entry.timePerQuestionSec}s na pytanie • aktualizacja ${formatHomeRelativeAge(entry.updatedAt, locale)}`,
  });

export function ActiveRivalCard({
  copy,
  entry,
  isActionPending,
  isCurrentLearner,
  isPending,
  locale: _locale,
  onChallenge,
}: {
  copy: CardCopy;
  entry: { displayName?: string; learnerId?: string };
  isActionPending: boolean;
  isCurrentLearner: boolean;
  isPending: boolean;
  locale: KangurMobileLocale;
  onChallenge: (() => void) | null;
}): React.JSX.Element {
  const name = entry.displayName ?? entry.learnerId ?? 'Rival';
  const actionLabel = isCurrentLearner
    ? extractText(copy, 'Duell-Rivale (Ty)')
    : extractText(
        copy,
        `Wyzwij: ${name}`,
      );
  const isBusy = isActionPending || isPending;
  const title = `${name} ${isCurrentLearner ? '· Ty' : ''}`.trim();

  return (
    <View
      style={{
        gap: 8,
        padding: 14,
        borderRadius: 20,
        backgroundColor: '#f8fafc',
        borderColor: '#e2e8f0',
        borderWidth: 1,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '700' }}>
        {title}
      </Text>
      <Pressable
        disabled={!onChallenge || isBusy}
        onPress={() => {
          onChallenge?.();
        }}
      >
        <Text style={{ color: '#3b82f6' }}>
          {actionLabel}
        </Text>
      </Pressable>
    </View>
  );
}

export function OutgoingChallengeCard({
  copy,
  entry,
  isSharing,
  locale,
  onShare,
}: {
  copy: CardCopy;
  entry: KangurDuelLobbyEntry;
  isSharing: boolean;
  locale: KangurMobileLocale;
  onShare: () => void;
}): React.JSX.Element {
  const seriesLine =
    entry.series === null || entry.series === undefined
      ? null
      : getHomeDuelSeriesLabel(entry.series, locale);

  return (
    <View
      style={{
        gap: 8,
        padding: 14,
        borderRadius: 20,
        backgroundColor: '#f8fafc',
        borderColor: '#e2e8f0',
        borderWidth: 1,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '700' }}>
        {extractText(copy, 'Prywatne wyzwanie')}
      </Text>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {entry.host?.displayName ?? 'Prywatne wyzwanie'}
      </Text>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {getModeOperationLine(copy, entry, locale)}
      </Text>
      <Text style={{ color: '#64748b' }}>{getUpdatedLine(copy, entry, locale)}</Text>
      {seriesLine === null ? null : (
        <Text style={{ color: '#4338ca', lineHeight: 20 }}>{seriesLine}</Text>
      )}
      <Pressable disabled={isSharing} onPress={() => onShare()}>
        <Text style={{ color: '#3b82f6' }}>
          {isSharing ? extractText(copy, 'Udostępnianie...') : extractText(copy, 'Udostępnij link')}
        </Text>
      </Pressable>
    </View>
  );
}

export function LiveDuelCard({
  copy,
  entry,
  isAuthenticated,
  locale,
}: {
  copy: CardCopy;
  entry: KangurDuelLobbyEntry;
  isAuthenticated: boolean;
  locale: KangurMobileLocale;
}): React.JSX.Element {
  const hostName = entry.host?.displayName ?? 'Sesja publiczna';
  const seriesLine =
    entry.series === null || entry.series === undefined
      ? null
      : getHomeDuelSeriesLabel(entry.series, locale);

  return (
    <View
      style={{
        gap: 8,
        padding: 14,
        borderRadius: 20,
        backgroundColor: '#f8fafc',
        borderColor: '#e2e8f0',
        borderWidth: 1,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '700' }}>{hostName}</Text>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {getModeOperationLine(copy, entry, locale)}
      </Text>
      <Text style={{ color: '#64748b' }}>{getUpdatedLine(copy, entry, locale)}</Text>
      {seriesLine === null ? null : (
        <Text style={{ color: '#4338ca', lineHeight: 20 }}>{seriesLine}</Text>
      )}
      <Pressable disabled={!isAuthenticated}>
        <Text style={{ color: '#3b82f6' }}>
          {isAuthenticated
            ? extractText(copy, 'Obserwuj na żywo')
            : extractText(copy, 'Zaloguj, aby obserwować')}
        </Text>
      </Pressable>
    </View>
  );
}

export function DuelLeaderboardSnapshotCard({
  copy,
  entry,
  locale: _locale,
  rank,
}: {
  copy: CardCopy;
  entry: { learnerId?: string; displayName?: string };
  locale: string;
  rank: number;
}): React.JSX.Element {
  return (
    <View
      style={{
        gap: 8,
        padding: 14,
        borderRadius: 20,
        backgroundColor: '#eff6ff',
        borderColor: '#bfdbfe',
        borderWidth: 1,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '700' }}>
